// 不用上游 web component，避免其把字体 CSS 注入 document.head；全部资产落 shadowRoot
import { parse, HtmlGenerator } from 'https://cdn.jsdelivr.net/npm/latex.js@0/+esm';
const base = 'https://cdn.jsdelivr.net/npm/latex.js@0.12.6/dist/';
const g = parse(data.latex, { generator:new HtmlGenerator({hyphenate:data.hyphenate ?? true}) });
const font = document.createElement('link'); font.rel = 'stylesheet'; font.href = `${base}fonts/cmu.css`;
const el = document.createElement('div'); el.className = 'page'; el.appendChild(g.domFragment());
shadowRoot.append(g.stylesAndScripts(base), font, el); g.applyLengthsAndGeometryToDom(el);
